  ('elementary-64311456-moex-00945', 'elementary-64311456', 'elementary-64311456-moex-110-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '案主自決（self-determination）是社會個案工作的重要價值觀，下列何種狀況符合案主自決的概念？', '["雖然獨居於會漏雨的瓦房中，但因其堅持不願離開曾跟老伴一起居住的地方，社會工作者並未將案主 安置到老人之家", "覺察未成年案主遭受家暴，但因案主堅持不想造成家庭紛爭，社會工作者並未通報", "與學生會談時發現該生遭受同學性侵害，因為案主害怕曝光，所以學校社會工作者並未通報", "因為案主表示沒有辦法向公司請假，所以容許案主不來接受性侵害加害者的強制處遇"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:12+00:00", "source_pdf_sha1": "afc9a1379873", "answer_pdf_sha1": "36be20ddb9c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00946', 'elementary-64311456', 'elementary-64311456-moex-110-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '有關社會工作者進行個案工作的敘述，下列何者正確？', '["社會工作者在服務過程中必須保持中立，所以不適合表達對案主遭受困境的同情", "基於案主自決，所以即使是會危害案主的生命，也要尊重案主的決定", "在提供服務時，應充分告知案主所有可能的選擇及其相對的優劣", "社會工作者服務的目標是以滿足案主提出的需求為優先"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:12+00:00", "source_pdf_sha1": "afc9a1379873", "answer_pdf_sha1": "36be20ddb9c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00947', 'elementary-64311456', 'elementary-64311456-moex-110-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '為了協助案主取得需要的資源，社會工作者需要採取一些行動或施行某些策略，下列何者為社會工作者 取得資源的常用策略？', '["同理、接納、傾聽", "教育、獎懲、增強", "連結、協商、倡導", "立法、管理、簽約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:12+00:00", "source_pdf_sha1": "afc9a1379873", "answer_pdf_sha1": "36be20ddb9c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00948', 'elementary-64311456', 'elementary-64311456-moex-110-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '下列何者是建立助人關係的關鍵技巧？', '["觀察、聚焦與回應", "評估、介入與反饋", "同理、尊重與真誠", "準備、銜接與記錄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:12+00:00", "source_pdf_sha1": "afc9a1379873", "answer_pdf_sha1": "36be20ddb9c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00949', 'elementary-64311456', 'elementary-64311456-moex-110-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '有關團體工作倫理價值的敘述，下列何者錯誤？', '["只要有團體經驗者就可以擔任團體的領導者", "團體領導者應確保每一個人隱私", "團體領導者應公平對待每一個成員", "維護成員的身心安全"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:12+00:00", "source_pdf_sha1": "afc9a1379873", "answer_pdf_sha1": "36be20ddb9c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
